def _parse(pattern):
    pos = [0]
    n = len(pattern)

    def peek():
        return pattern[pos[0]] if pos[0] < n else None

    def parse_alt():
        options = [parse_concat()]
        while peek() == '|':
            pos[0] += 1
            options.append(parse_concat())
        if len(options) == 1:
            return options[0]
        return ('alt', options)

    def parse_concat():
        nodes = []
        while True:
            c = peek()
            if c is None or c == '|' or c == ')':
                break
            nodes.append(parse_quantified())
        if len(nodes) == 1:
            return nodes[0]
        return ('seq', nodes)

    def parse_quantified():
        atom = parse_atom()
        c = peek()
        if c == '*':
            pos[0] += 1
            return ('star', atom)
        if c == '+':
            pos[0] += 1
            return ('plus', atom)
        if c == '?':
            pos[0] += 1
            return ('opt', atom)
        return atom

    def parse_atom():
        c = peek()
        if c == '(':
            pos[0] += 1
            node = parse_alt()
            pos[0] += 1  # consume ')'
            return node
        if c == '[':
            return parse_class()
        if c == '.':
            pos[0] += 1
            return ('any',)
        pos[0] += 1
        return ('char', c)

    def parse_class():
        pos[0] += 1  # consume '['
        negated = False
        if peek() == '^':
            negated = True
            pos[0] += 1
        items = []
        while peek() != ']':
            lo = pattern[pos[0]]
            pos[0] += 1
            if peek() == '-' and pos[0] + 1 < n and pattern[pos[0] + 1] != ']':
                pos[0] += 1  # consume '-'
                hi = pattern[pos[0]]
                pos[0] += 1
                items.append((lo, hi))
            else:
                items.append((lo, lo))
        pos[0] += 1  # consume ']'
        return ('class', negated, items)

    return parse_alt()


def _class_match(node, ch):
    negated = node[1]
    found = False
    for lo, hi in node[2]:
        if lo <= ch <= hi:
            found = True
            break
    return found != negated


def _match_node(node, s, i, k):
    t = node[0]
    if t == 'char':
        if i < len(s) and s[i] == node[1]:
            return k(i + 1)
        return False
    if t == 'any':
        if i < len(s):
            return k(i + 1)
        return False
    if t == 'class':
        if i < len(s) and _class_match(node, s[i]):
            return k(i + 1)
        return False
    if t == 'seq':
        nodes = node[1]

        def step(idx, p):
            if idx == len(nodes):
                return k(p)
            return _match_node(nodes[idx], s, p, lambda np: step(idx + 1, np))

        return step(0, i)
    if t == 'alt':
        for opt in node[1]:
            if _match_node(opt, s, i, k):
                return True
        return False
    if t == 'star':
        sub = node[1]

        def more(p):
            def cont(np):
                if np == p:
                    return False
                return more(np)
            if _match_node(sub, s, p, cont):
                return True
            return k(p)

        return more(i)
    if t == 'plus':
        sub = node[1]
        return _match_node(sub, s, i,
                           lambda np: _match_node(('star', sub), s, np, k))
    if t == 'opt':
        sub = node[1]
        if _match_node(sub, s, i, k):
            return True
        return k(i)
    return False


def match(pattern: str, text: str) -> bool:
    ast = _parse(pattern)
    return _match_node(ast, text, 0, lambda p: p == len(text))
